import math

print("Redondeo hacia arriba de 4.1:", math.ceil(4.1)) # Redondea hacia arriba
print("Redondeo hacia abajo de 5.9:", math.floor(5.9)) # Redondea hacia abajo
print("Truncamiento de 7.3:", math.trunc(7.3)) # Elimina la parte decimal, dejando solo la parte entera
print("Valor absoluto de 25:", math.fabs(25)) # Devuelve el valor absoluto de un número, es decir, su valor sin importar si es positivo o negativo. En este caso, devuelve 25
print("Valor absoluto de -25:", math.fabs(-25)) # Devuelve el valor absoluto de un número, es decir, su valor sin importar si es positivo o negativo. En este caso, devuelve 25
print("Factorial de 5:", math.factorial(5)) # Devuelve el factorial de un número, que es el producto de todos los enteros positivos desde 1 hasta ese número. En este caso, devuelve 120 (1*2*3*4*5)
print("Resto de la división de 10 entre 3 (10 % 3 = 9 + '1'):", math.fmod(10, 3)) # Devuelve el resto de la división de 10 entre 3, que es 1
print("Raíz cuadrada de 16:", math.sqrt(16)) # Devuelve la raíz cuadrada de 16, que es 4